-- ----------------------------
-- Table structure for asset_acceptance
-- ----------------------------
DROP TABLE IF EXISTS `asset_acceptance`;
CREATE TABLE `asset_acceptance`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '验收ID',
  `acceptance_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL COMMENT '验收编码',
  `purchase_id` bigint NULL DEFAULT NULL COMMENT '申购ID',
  `supplier_id` bigint NULL DEFAULT NULL COMMENT '供应商ID',
  `acceptance_person_id` bigint NULL DEFAULT NULL COMMENT '验收人ID',
  `invoice_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '发票号码',
  `contract_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '合同编号',
  `acceptance_result` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT 'PASS' COMMENT '验收结果：PASS-合格，FAIL-不合格',
  `business_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT 'pending' COMMENT '业务状态：pending-待验收，completed-已完成',
  `acceptance_date` date NOT NULL COMMENT '验收日期',
  `qualified_quantity` int NULL DEFAULT 0 COMMENT '合格数量',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '备注',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT '0' COMMENT '删除标志（0代表存在 2代表删除）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_acceptance_code`(`acceptance_code` ASC) USING BTREE,
  INDEX `idx_purchase_id`(`purchase_id` ASC) USING BTREE,
  INDEX `idx_supplier_id`(`supplier_id` ASC) USING BTREE,
  INDEX `idx_business_status`(`business_status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_as_ci COMMENT = '资产验收表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of asset_acceptance
-- ----------------------------

-- ----------------------------
-- Table structure for asset_assets
-- ----------------------------
DROP TABLE IF EXISTS `asset_assets`;
CREATE TABLE `asset_assets`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '资产ID',
  `asset_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL COMMENT '资产编码',
  `category_id` bigint NULL DEFAULT NULL COMMENT '分类ID',
  `supplier_id` bigint NULL DEFAULT NULL COMMENT '供应商ID',
  `dept_id` bigint NULL DEFAULT NULL COMMENT '使用部门ID',
  `user_id` bigint NULL DEFAULT NULL COMMENT '使用人ID',
  `asset_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL COMMENT '资产名称',
  `asset_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '资产类型',
  `asset_source` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '资产来源',
  `model` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '规格型号',
  `brand` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '品牌',
  `serial_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '序列号',
  `unit` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '单位',
  `location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '存放位置',
  `longitude` decimal(10, 7) NULL DEFAULT NULL COMMENT '经度',
  `latitude` decimal(10, 7) NULL DEFAULT NULL COMMENT '纬度',
  `asset_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL DEFAULT 'PENDING_IN' COMMENT '资产状态',
  `barcode` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '条码',
  `rfid_tag` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT 'RFID标签',
  `quantity` int NULL DEFAULT 1 COMMENT '数量',
  `original_value` decimal(20, 2) NULL DEFAULT 0.00 COMMENT '原值',
  `salvage_value` decimal(20, 2) NULL DEFAULT 0.00 COMMENT '残值',
  `depreciation_method` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '折旧方法',
  `depreciation_rate` decimal(10, 4) NULL DEFAULT NULL COMMENT '折旧率',
  `accumulated_depreciation` decimal(20, 2) NULL DEFAULT 0.00 COMMENT '累计折旧',
  `net_value` decimal(20, 2) NULL DEFAULT 0.00 COMMENT '净值',
  `depreciation_start_date` date NULL DEFAULT NULL COMMENT '开始折旧日期',
  `purchase_date` date NULL DEFAULT NULL COMMENT '采购日期',
  `purchase_price` decimal(20, 2) NULL DEFAULT NULL COMMENT '购置价格',
  `warranty_expire_date` date NULL DEFAULT NULL COMMENT '保修截止日期',
  `manufacture_date` date NULL DEFAULT NULL COMMENT '生产日期',
  `start_use_date` date NULL DEFAULT NULL COMMENT '开始使用日期',
  `scrap_date` date NULL DEFAULT NULL COMMENT '报废日期',
  `main_image` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '主图片',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '备注',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT '0' COMMENT '删除标志（0代表存在 2代表删除）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_asset_code`(`asset_code` ASC) USING BTREE,
  INDEX `idx_category_id`(`category_id` ASC) USING BTREE,
  INDEX `idx_asset_status`(`asset_status` ASC) USING BTREE,
  INDEX `idx_dept_id`(`dept_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_supplier_id`(`supplier_id` ASC) USING BTREE,
  CONSTRAINT `fk_assets_category` FOREIGN KEY (`category_id`) REFERENCES `asset_category` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT,
  CONSTRAINT `fk_assets_dept` FOREIGN KEY (`dept_id`) REFERENCES `sys_dept` (`dept_id`) ON DELETE SET NULL ON UPDATE RESTRICT,
  CONSTRAINT `fk_assets_supplier` FOREIGN KEY (`supplier_id`) REFERENCES `asset_supplier` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT,
  CONSTRAINT `fk_assets_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`user_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 102 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_as_ci COMMENT = '资产台账表' ROW_FORMAT = DYNAMIC;

