DROP TABLE IF EXISTS `asset_capitalize`;
CREATE TABLE `asset_capitalize`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '转固ID',
  `capitalize_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL COMMENT '转固编码',
  `acceptance_id` bigint NULL DEFAULT NULL COMMENT '验收ID',
  `asset_id` bigint NULL DEFAULT NULL COMMENT '资产ID',
  `capitalize_date` date NOT NULL COMMENT '转固日期',
  `original_value` decimal(20, 2) NULL DEFAULT NULL COMMENT '转固原值',
  `depreciation_start_date` date NULL DEFAULT NULL COMMENT '开始折旧日期',
  `business_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT 'pending' COMMENT '业务状态：pending-待转固，completed-已完成',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '备注',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT '0' COMMENT '删除标志（0代表存在 2代表删除）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_capitalize_code`(`capitalize_code` ASC) USING BTREE,
  INDEX `idx_acceptance_id`(`acceptance_id` ASC) USING BTREE,
  INDEX `idx_asset_id`(`asset_id` ASC) USING BTREE,
  INDEX `idx_business_status`(`business_status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_as_ci COMMENT = '资产转固表' ROW_FORMAT = Dynamic;

