-- Table structure for asset_change_detail_backup
-- ----------------------------
DROP TABLE IF EXISTS `asset_change_detail_backup`;
CREATE TABLE `asset_change_detail_backup`  (
  `id` bigint NOT NULL DEFAULT 0 COMMENT '主键ID',
  `master_id` bigint NOT NULL COMMENT '主表ID',
  `asset_id` bigint NOT NULL COMMENT '资产ID',
  `change_content` json NULL COMMENT '变更内容(JSON格式)',
