-- ----------------------------
-- Table structure for asset_depreciation
-- ----------------------------
DROP TABLE IF EXISTS `asset_depreciation`;
CREATE TABLE `asset_depreciation`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `asset_id` bigint NOT NULL COMMENT '资产ID',
  `depreciation_period` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL COMMENT '折旧期间',
  `depreciation_date` date NOT NULL COMMENT '折旧日期',
  `period_year` int NOT NULL COMMENT '年份',
  `period_month` int NOT NULL COMMENT '月份',
  `depreciation_amount` decimal(20, 2) NULL DEFAULT NULL COMMENT '折旧金额',
  `accumulated_depreciation` decimal(20, 2) NULL DEFAULT NULL COMMENT '累计折旧',
  `net_value` decimal(20, 2) NULL DEFAULT NULL COMMENT '净值',
  `business_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT 'completed' COMMENT '业务状态：pending-待折旧，completed-已折旧',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT '0' COMMENT '删除标志',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_asset_id`(`asset_id` ASC) USING BTREE,
  INDEX `idx_depreciation_period`(`depreciation_period` ASC) USING BTREE,
  INDEX `idx_business_status`(`business_status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_as_ci COMMENT = '资产折旧记录表' ROW_FORMAT = Dynamic;

