-- Records of asset_depreciation
-- ----------------------------

-- ----------------------------
-- Table structure for asset_disposal
-- ----------------------------
DROP TABLE IF EXISTS `asset_disposal`;
CREATE TABLE `asset_disposal`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `disposal_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL COMMENT '处置编码',
  `asset_id` bigint NULL DEFAULT NULL COMMENT '资产ID',
  `disposal_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '处置类型',
  `disposal_date` date NULL DEFAULT NULL COMMENT '处置日期',
  `business_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT 'draft' COMMENT '业务状态：draft-草稿，pending-待审批，approved-已批准，completed-已完成',
  `proc_inst_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '流程实例ID',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '备注',
