-- ----------------------------
-- Table structure for asset_inventory
-- ----------------------------
DROP TABLE IF EXISTS `asset_inventory`;
CREATE TABLE `asset_inventory`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '盘点ID',
  `inventory_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL COMMENT '盘点单编码',
  `inventory_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '盘点名称',
  `inventory_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '盘点类型',
  `dept_id` bigint NULL DEFAULT NULL COMMENT '盘点部门ID',
  `inventory_person_id` bigint NULL DEFAULT NULL COMMENT '盘点人ID',
  `inventory_date` date NULL DEFAULT NULL COMMENT '盘点日期',
  `planned_start_date` date NULL DEFAULT NULL COMMENT '计划开始日期',
  `planned_end_date` date NULL DEFAULT NULL COMMENT '计划结束日期',
  `actual_start_date` date NULL DEFAULT NULL COMMENT '实际开始日期',
  `actual_end_date` date NULL DEFAULT NULL COMMENT '实际结束日期',
  `business_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT 'pending' COMMENT '业务状态：pending-待盘点，processing-盘点中，completed-已完成',
  `total_assets` bigint NULL DEFAULT 0 COMMENT '总资产数',
  `inventoried_count` bigint NULL DEFAULT 0 COMMENT '已盘点数',
  `surplus_count` bigint NULL DEFAULT 0 COMMENT '盘盈数',
  `shortage_count` bigint NULL DEFAULT 0 COMMENT '盘亏数',
  `completion_rate` decimal(5, 2) NULL DEFAULT 0.00 COMMENT '完成率',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '备注',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT '0' COMMENT '删除标志',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_inventory_code`(`inventory_code` ASC) USING BTREE,
  INDEX `idx_dept_id`(`dept_id` ASC) USING BTREE,
  INDEX `idx_business_status`(`business_status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_as_ci COMMENT = '资产盘点主表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of asset_inventory
