-- ----------------------------
-- Table structure for asset_inventory_detail
-- ----------------------------
DROP TABLE IF EXISTS `asset_inventory_detail`;
CREATE TABLE `asset_inventory_detail`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '明细ID',
  `master_id` bigint NOT NULL COMMENT '关联主表ID',
  `asset_id` bigint NOT NULL COMMENT '资产ID',
  `theoretical_quantity` int NULL DEFAULT 0 COMMENT '账面数量',
  `actual_quantity` int NULL DEFAULT 0 COMMENT '实盘数量',
  `difference` int NULL DEFAULT 0 COMMENT '差异数量',
  `inventory_result` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '盘点结果：NORMAL-正常，MISSING-盘亏，SURPLUS-盘盈，DAMAGED-损坏',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `inventory_time` datetime NULL DEFAULT NULL COMMENT '盘点时间',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标志',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_master_id`(`master_id` ASC) USING BTREE,
  INDEX `idx_asset_id`(`asset_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '资产盘点明细表' ROW_FORMAT = Dynamic;

