DROP TABLE IF EXISTS `asset_split`;
CREATE TABLE `asset_split`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '拆分ID',
  `split_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL COMMENT '拆分单编码',
  `source_asset_id` bigint NOT NULL COMMENT '原资产ID',
  `split_reason` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '拆分原因',
  `split_date` date NOT NULL COMMENT '拆分日期',
  `split_quantity` int NOT NULL COMMENT '拆分总数（被拆出的数量）',
  `business_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL DEFAULT 'draft' COMMENT '业务状态：draft-草稿，pending-办理中，rejected-已退回，completed-已完成',
  `approver_id` bigint NULL DEFAULT NULL COMMENT '审批人ID',
  `approve_time` datetime NULL DEFAULT NULL COMMENT '审批时间',
  `proc_inst_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT 'Activiti流程实例ID',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '备注',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT '0' COMMENT '删除标志（0代表存在 2代表删除）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_split_code`(`split_code` ASC) USING BTREE,
  INDEX `idx_source_asset_id`(`source_asset_id` ASC) USING BTREE,
  INDEX `idx_business_status`(`business_status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_as_ci COMMENT = '资产拆分明细表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of asset_split
-- ----------------------------

-- ----------------------------
-- Table structure for asset_split_attachment
-- ----------------------------
DROP TABLE IF EXISTS `asset_split_attachment`;
CREATE TABLE `asset_split_attachment`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '附件ID',
  `master_id` bigint NOT NULL COMMENT '拆分单ID',
  `attachment_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '附件名称',
  `attachment_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '附件类型',
  `file_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '附件URL',
  `upload_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '上传人',
  `upload_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '上传时间',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标志',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_master_id`(`master_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '资产拆分附件表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of asset_split_attachment
-- ----------------------------

-- ----------------------------
-- Table structure for asset_split_result
-- ----------------------------
DROP TABLE IF EXISTS `asset_split_result`;
CREATE TABLE `asset_split_result`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `split_id` bigint NOT NULL COMMENT '拆分单ID',
  `new_asset_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL COMMENT '新资产编码',
  `new_asset_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL COMMENT '新资产名称',
  `split_quantity` int NOT NULL DEFAULT 1 COMMENT '拆分数量',
  `original_value` decimal(20, 2) NULL DEFAULT NULL COMMENT '分摊原值',
  `user_id` bigint NULL DEFAULT NULL COMMENT '使用人ID',
  `dept_id` bigint NULL DEFAULT NULL COMMENT '使用部门ID',
  `location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '存放位置',
  `execute_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL DEFAULT 'pending' COMMENT '执行状态：pending-待执行，executing-执行中，success-执行成功，fail-执行失败',
  `target_asset_id` bigint NULL DEFAULT NULL COMMENT '生成的资产ID',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `create_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '创建人',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '更新人',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT '0' COMMENT '删除标志（0代表存在 2代表删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_split_id`(`split_id` ASC) USING BTREE,
  INDEX `idx_new_asset_code`(`new_asset_code` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_as_ci COMMENT = '资产拆分结果表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of asset_split_result
-- ----------------------------

