DROP TABLE IF EXISTS `asset_storage`;
CREATE TABLE `asset_storage`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `storage_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NOT NULL COMMENT '入库单号',
  `storage_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '入库类型：purchase-采购，transfer-调拨，return-归还',
  `applicant_id` bigint NULL DEFAULT NULL COMMENT '申请人ID',
  `applicant_dept_id` bigint NULL DEFAULT NULL COMMENT '申请部门ID',
  `apply_date` date NULL DEFAULT NULL COMMENT '申请日期',
  `business_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT 'draft' COMMENT '业务状态：draft-草稿，pending-待审批，rejected-已退回，completed-已完成',
  `proc_inst_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '流程实例ID',
  `total_amount` decimal(18, 2) NULL DEFAULT 0.00 COMMENT '总金额',
  `asset_count` int NULL DEFAULT 0 COMMENT '资产数量',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT NULL COMMENT '备注',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_ci NULL DEFAULT '0' COMMENT '删除标志',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_storage_code`(`storage_code` ASC) USING BTREE,
  INDEX `idx_applicant_id`(`applicant_id` ASC) USING BTREE,
  INDEX `idx_business_status`(`business_status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_as_ci COMMENT = '资产入库表' ROW_FORMAT = Dynamic;

