INSERT INTO `sys_menu` VALUES (2705, '审批', 2594, 1, '', NULL, NULL, '', 1, 0, 'F', '0', '0', 'asset:change:approve', '#', 'admin', '2026-04-26 17:29:45', '', NULL, '资产变动审批按钮');
INSERT INTO `sys_menu` VALUES (2800, '名下资产', 0, 5, 'asset/my', 'asset/my/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:assets:list', 'asset-under-name', 'admin', '2026-05-07 13:20:22', 'admin', '2026-05-17 11:14:51', '展示当前登录用户所拥有或使用的资产列表，支持查看资产详情、打印标签、申请维修/报废/交回等操作。业务逻辑：关联资产领用记录，展示user_id等于当前用户的资产卡片。');
INSERT INTO `sys_menu` VALUES (2801, '资产配置计划', 0, 6, 'asset/plan', 'asset/plan/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:plan:list', 'asset-plan', 'admin', '2026-05-07 13:20:22', 'admin', '2026-05-17 11:15:59', '资产采购/配置计划管理。业务逻辑：各部门提交年度/季度资产配置需求 → 预算审批 → 计划汇总 → 生成采购单。包含计划编制、计划审批、计划执行跟踪功能。');
INSERT INTO `sys_menu` VALUES (2810, '资产收入库审批', 2591, 1, 'storage/approve', 'asset/storage/approve/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:storage:approve', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '采购入库审批。业务逻辑：资产管理员提交入库申请 → 部门负责人审批 → 资产入库 → 生成资产卡片。支持批量审批、驳回、转审。');
INSERT INTO `sys_menu` VALUES (2811, '资产领用审批', 2591, 2, 'receive/approve', 'asset/receive/approve/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:receive:approve', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产领用审批。业务逻辑：员工提交领用申请 → 部门负责人审批 → 资产管理员确认 → 资产状态变更为\"使用中\"。支持查看资产库存。');
INSERT INTO `sys_menu` VALUES (2812, '资产交回审批', 2591, 3, 'return/approve', 'asset/return/approve/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:return:approve', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产交回/退库审批。业务逻辑：员工提交交回申请 → 资产管理员确认 → 资产状态变更为\"在库\"。支持离职/调岗时的资产交回。');
INSERT INTO `sys_menu` VALUES (2813, '资产内部处置审批', 2591, 4, 'disposal/approve', 'asset/disposal/approve/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:disposal:approve', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产内部处置审批。业务逻辑：资产管理员提交处置申请（报废/转让/捐赠）→ 部门领导审批 → 财务审批 → 资产状态变更。');
INSERT INTO `sys_menu` VALUES (2814, '资产调出审批', 2591, 5, 'transferOut/approve', 'asset/transfer/approve/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:transferOut:approve', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产调出审批（跨部门/跨公司）。业务逻辑：调出方提交调拨申请 → 调出方领导审批 → 调入方领导确认 → 资产管理员执行调拨。');
INSERT INTO `sys_menu` VALUES (2815, '资产调入审批', 2591, 6, 'transferIn/approve', 'asset/transfer/approve/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:transferIn:approve', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产调入确认。业务逻辑：收到调出方调拨申请 → 调入部门负责人确认接收 → 资产管理员变更资产使用部门。');
INSERT INTO `sys_menu` VALUES (2816, '名下资产交接审批', 2591, 7, 'handover/approve', 'asset/transfer/approve/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:handover:approve', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '名下资产交接审批。业务逻辑：员工离职/调岗时，将其名下资产交接给接收人 → 交接双方确认 → 资产管理员审核 → 资产使用人变更。');
INSERT INTO `sys_menu` VALUES (2817, '资产维修维护审批', 2591, 9, 'maintain/approve', 'asset/maintain/approve/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:maintain:approve', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产维修/维护审批。业务逻辑：使用人提交维修申请 → 部门审批 → 资产管理员安排维修 → 维修完成确认。支持维修费用登记。');
INSERT INTO `sys_menu` VALUES (2820, '入库申请查询', 2592, 1, 'storage/query', 'asset/storage/query/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:storage:query', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产入库申请记录查询。支持按申请人、申请时间、审批状态、资产分类等条件查询。可查看审批进度和审批意见。');
INSERT INTO `sys_menu` VALUES (2821, '领用申请查询', 2592, 2, 'receive/query', 'asset/receive/query/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:receive:query', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产领用申请记录查询。支持按申请人、领用部门、领用时间、审批状态查询。可查看领用明细和资产去向。');
INSERT INTO `sys_menu` VALUES (2822, '交回申请查询', 2592, 3, 'return/query', 'asset/return/query/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:return:query', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产交回/退库申请记录查询。支持按交回人、交回时间、资产编号查询。适用于离职审计、资产追溯场景。');
INSERT INTO `sys_menu` VALUES (2823, '处置申请查询', 2592, 4, 'disposal/query', 'asset/disposal/query/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:disposal:query', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产处置申请记录查询。支持按处置类型（报废/捐赠/转让）、处置时间、审批状态查询。可查看处置收入和凭证。');
INSERT INTO `sys_menu` VALUES (2824, '调拨申请查询', 2592, 5, 'transfer/query', 'asset/transfer/query/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:transfer:query', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产调拨申请记录查询。支持按调出部门、调入部门、调拨时间、审批状态查询。可查看资产调拨轨迹。');
INSERT INTO `sys_menu` VALUES (2825, '维修申请查询', 2592, 6, 'maintain/query', 'asset/maintain/query/index', NULL, '', 1, 0, 'C', '0', '0', 'asset:maintain:query', '#', 'admin', '2026-05-07 13:20:23', NULL, NULL, '资产维修/维护申请记录查询。支持按维修资产、维修时间、维修费用、完成状态查询。可查看维修历史。');
